from flask import Flask, request, jsonify
import psycopg2

app = Flask(__name__)

def connect_to_db():
    try:
        conn = psycopg2.connect(database="mydatabase", user="foo", password="bar", host="127.0.0.1", port="5432")
        return conn
    except Exception as e:
        print("Unable to connect to the database", e)

@app.route('/invoices', methods=['GET'])
def get_all_invoices():
    conn = connect_to_db()
    cur = conn.cursor()
    cur.execute('SELECT * FROM invoices')
    rows = cur.fetchall()

    return jsonify(rows)

@app.route('/invoice', methods=['POST'])
def add_invoice():
    data = request.get_json()
    conn = connect_to_db()
    cur = conn.cursor()
    cur.execute('INSERT INTO invoices (customer, amount) VALUES (%s, %s)', (data['customer'], data['amount']))

    return jsonify({"message": "invoice added successfully"}), 201

if __name__ == '__main__':
    app.run(debug=True)
